+fn header_has_token(req: &Http1Request, name: &str, token: &str) -> bool {
+    header_value(req, name).is_some_and(|value| {
+        value
+            .split(',')
+            .any(|segment| segment.trim().eq_ignore_ascii_case(token))
+    })
